const customPreset = (raw) => {
  const svc = (raw || "Your Service").trim();
  const Svc = svc.replace(/\b\w/g, (c) => c.toUpperCase());
  return {
    label: "Custom", service: svc.toLowerCase(), primary: "#1f2933", accent: "#2f80ed",
    name: `${Svc.toUpperCase()} CO.`, headline: `Reliable ${Svc}`, subhead: "Dependable Service, Every Time.",
  };
};

