function Btn({ children, href, theme, variant = "outline", narrow }) {
  const base = "inline-block font-semibold hover:opacity-90 transition";
  const style =
    variant === "outline"
      ? { border: `2px solid ${theme.accent}`, color: "#fff", padding: "12px 32px", fontSize: narrow ? 16 : 20 }
      : { background: "#fff", color: theme.primary, padding: "13px 30px" };
  return (
    <a href={href || undefined} target="_blank" rel="noreferrer" className={base} style={style}>
      {children}
    </a>
  );
}

