const BLOCK_DEFAULTS = {
  title: { type: "title", text: "New Title", size: 32, color: "#ffffff", font: "", align: "center", bold: true, italic: false, underline: false },
  text: { type: "text", text: "New text block. Edit me.", size: 18, color: "#cbd5e1", font: "", align: "center", bold: false, italic: false, underline: false },
  button: { type: "button", label: "Click Here", kind: "website", value: "", align: "center" },
  linkbox: { type: "linkbox", label: "Request Service", kind: "phone", value: "", align: "center", style: "solid" },
  image: { type: "image", src: "", width: 80, align: "center" },
  divider: { type: "divider" },
  spacer: { type: "spacer", h: 40 },
  columns: { type: "columns", left: "Left column text. Edit me.", right: "Right column text. Edit me.", size: 16, color: "#cbd5e1" },
  video: { type: "video", url: "" },
  map: { type: "map", query: "" },
  table: { type: "table", table: { headers: ["Column 1", "Column 2"], rows: [["", ""], ["", ""]] } },
  quote: { type: "quote", text: "A short, powerful quote.", who: "", size: 24, color: "#ffffff" },
  embed: { type: "embed", html: "" },
};

const BLOCK_LABELS = { linkbox: "Link box" };
const blockLabel = (t) => BLOCK_LABELS[t] || t.charAt(0).toUpperCase() + t.slice(1);

const blockTextStyle = (b) => ({
  fontSize: b.size,
  color: b.color,
  fontFamily: b.font ? FONTS[b.font]?.stack : "inherit",
  textAlign: b.align,
  fontWeight: b.bold ? 700 : 400,
  fontStyle: b.italic ? "italic" : "normal",
  textDecoration: b.underline ? "underline" : "none",
});

function videoEmbed(url) {
  if (!url) return "";
  const yt = url.match(/(?:youtu\.be\/|youtube\.com\/(?:watch\?v=|embed\/|shorts\/))([\w-]{11})/);
  if (yt) return `https://www.youtube.com/embed/${yt[1]}`;
  const vm = url.match(/vimeo\.com\/(\d+)/);
  if (vm) return `https://player.vimeo.com/video/${vm[1]}`;
  return url;
}

function CustomBlocksView({ blocks, site, narrow }) {
  const theme = site.theme;
  if (!blocks || !blocks.length) return null;
  return (
    <div style={{ background: theme.primary }} className="px-6 py-8">
      {blocks.map((b, i) => {
        if (b.type === "divider") return <div key={i} className="mx-auto my-6 h-px w-full max-w-3xl" style={{ background: "rgba(255,255,255,0.15)" }} />;
        if (b.type === "spacer") return <div key={i} style={{ height: b.h }} />;
        if (b.type === "image") return b.src ? (
          <img key={i} src={b.src} alt="" className="my-4" style={{ width: `${b.width}%`, marginLeft: b.align === "right" ? "auto" : b.align === "center" ? "auto" : 0, marginRight: b.align === "left" ? "auto" : b.align === "center" ? "auto" : 0, display: "block", borderRadius: 8 }} />
        ) : null;
        if (b.type === "button") return (
          <div key={i} className="my-4" style={{ textAlign: b.align }}>
            <Btn theme={theme} variant="solid" href={actionHref(b, site.booking)}>{b.label}</Btn>
          </div>
        );
        if (b.type === "linkbox") {
          const href = actionHref(b, site.booking);
          const solid = b.style !== "outline";
          return (
            <div key={i} className="my-4" style={{ textAlign: b.align }}>
              <a href={href || undefined} target="_blank" rel="noreferrer"
                style={{ display: "inline-block", minWidth: narrow ? 200 : 260, padding: "16px 30px", textAlign: "center", border: "2px solid #fff", background: solid ? "#fff" : "transparent", color: solid ? theme.primary : "#fff", fontWeight: 600, letterSpacing: 0.3, textDecoration: "none" }}>
                {b.label}
              </a>
            </div>
          );
        }
        if (b.type === "columns") return (
          <div key={i} className={`max-w-4xl mx-auto my-4 grid gap-6 ${narrow ? "" : "grid-cols-2"}`}>
            <p style={{ fontSize: b.size, color: b.color }}>{b.left}</p>
            <p style={{ fontSize: b.size, color: b.color }}>{b.right}</p>
          </div>
        );
        if (b.type === "video") { const e = videoEmbed(b.url); return e ? (
          <div key={i} className="max-w-3xl mx-auto my-5" style={{ position: "relative", paddingTop: "56.25%" }}>
            <iframe src={e} title="video" allowFullScreen style={{ position: "absolute", inset: 0, width: "100%", height: "100%", border: 0, borderRadius: 8 }} />
          </div>
        ) : <div key={i} className="max-w-3xl mx-auto my-5 rounded-lg border border-dashed border-white/20 p-8 text-center text-slate-400 text-sm">Paste a YouTube or Vimeo link</div>; }
        if (b.type === "map") return b.query ? (
          <div key={i} className="max-w-3xl mx-auto my-5">
            <iframe title="map" src={`https://www.google.com/maps?q=${encodeURIComponent(b.query)}&output=embed`} style={{ width: "100%", height: 280, border: 0, borderRadius: 8 }} />
          </div>
        ) : <div key={i} className="max-w-3xl mx-auto my-5 rounded-lg border border-dashed border-white/20 p-8 text-center text-slate-400 text-sm">Enter an address to show a map</div>;
        if (b.type === "table") return <PreviewTable key={i} table={b.table} theme={theme} narrow={narrow} />;
        if (b.type === "quote") return (
          <blockquote key={i} className="max-w-2xl mx-auto my-6 text-center" style={{ borderLeft: `3px solid ${theme.accent}`, paddingLeft: 18 }}>
            <p style={{ fontSize: b.size, color: b.color, fontStyle: "italic" }}>{b.text}</p>
            {b.who && <footer className="mt-2 text-slate-400 text-sm">— {b.who}</footer>}
          </blockquote>
        );
        if (b.type === "embed") return b.html ? <div key={i} className="max-w-3xl mx-auto my-4" dangerouslySetInnerHTML={{ __html: b.html }} /> : null;
        const Tag = b.type === "title" ? "h2" : "p";
        return <Tag key={i} className="max-w-3xl mx-auto my-3 leading-snug" style={blockTextStyle(b)}>{b.text}</Tag>;
      })}
    </div>
  );
}

function customBlocksHTML(blocks, site) {
  const theme = site.theme;
  if (!blocks || !blocks.length) return "";
  const esc2 = (s = "") => String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const inner = blocks.map((b) => {
    if (b.type === "divider") return `<hr class="rule" style="margin:24px auto">`;
    if (b.type === "spacer") return `<div style="height:${b.h}px"></div>`;
    if (b.type === "image") return b.src ? `<img src="${b.src}" alt="" style="display:block;width:${b.width}%;margin:16px ${b.align === "left" ? "0 16px 0" : "auto"};border-radius:8px">` : "";
    if (b.type === "button") {
      const href = actionHref(b, site.booking);
      const a = href ? `<a class="solid" href="${href}" target="_blank" rel="noreferrer">${esc2(b.label)}</a>` : `<span class="solid">${esc2(b.label)}</span>`;
      return `<div style="text-align:${b.align};margin:16px 0">${a}</div>`;
    }
    if (b.type === "linkbox") {
      const href = actionHref(b, site.booking);
      const solid = b.style !== "outline";
      const css = `display:inline-block;min-width:260px;padding:16px 30px;text-align:center;border:2px solid #fff;background:${solid ? "#fff" : "transparent"};color:${solid ? theme.primary : "#fff"};font-weight:600;letter-spacing:.3px;text-decoration:none`;
      const a = href ? `<a href="${href}" target="_blank" rel="noreferrer" style="${css}">${esc2(b.label)}</a>` : `<span style="${css}">${esc2(b.label)}</span>`;
      return `<div style="text-align:${b.align};margin:16px 0">${a}</div>`;
    }
    if (b.type === "columns") return `<div style="max-width:900px;margin:16px auto;display:grid;grid-template-columns:1fr 1fr;gap:24px"><p style="font-size:${b.size}px;color:${b.color}">${esc2(b.left)}</p><p style="font-size:${b.size}px;color:${b.color}">${esc2(b.right)}</p></div>`;
    if (b.type === "video") { const e = videoEmbed(b.url); return e ? `<div style="max-width:760px;margin:20px auto;position:relative;padding-top:56.25%"><iframe src="${e}" allowfullscreen style="position:absolute;inset:0;width:100%;height:100%;border:0;border-radius:8px"></iframe></div>` : ""; }
    if (b.type === "map") return b.query ? `<div style="max-width:760px;margin:20px auto"><iframe src="https://www.google.com/maps?q=${encodeURIComponent(b.query)}&output=embed" style="width:100%;height:280px;border:0;border-radius:8px"></iframe></div>` : "";
    if (b.type === "table") return `<div class="tablewrap" style="max-width:900px;margin:16px auto">${tableHTML(b.table, theme)}</div>`;
    if (b.type === "quote") return `<blockquote style="max-width:640px;margin:24px auto;text-align:center;border-left:3px solid ${theme.accent};padding-left:18px"><p style="font-size:${b.size}px;color:${b.color};font-style:italic">${esc2(b.text)}</p>${b.who ? `<footer style="margin-top:8px;color:#94a3b8;font-size:14px">— ${esc2(b.who)}</footer>` : ""}</blockquote>`;
    if (b.type === "embed") return b.html ? `<div style="max-width:760px;margin:16px auto">${b.html}</div>` : "";
    const tag = b.type === "title" ? "h2" : "p";
    const css = `font-size:${b.size}px;color:${b.color};text-align:${b.align};font-weight:${b.bold ? 700 : 400};font-style:${b.italic ? "italic" : "normal"};text-decoration:${b.underline ? "underline" : "none"};${b.font ? `font-family:${FONTS[b.font]?.stack}` : ""};max-width:760px;margin:12px auto`;
    return `<${tag} style="${css}">${esc2(b.text)}</${tag}>`;
  }).join("");
  return `<section style="padding:32px 24px">${inner}</section>`;
}

/* ---------- reusable table (preview + export) ---------- */
/* ---------- inline (click-to-edit) helpers ---------- */
function Editable({ value, onCommit, as: Tag = "span", className, style, multiline }) {
  if (!onCommit) return <Tag className={className} style={style}>{value}</Tag>;
  return (
    <Tag
      className={className}
      style={{ ...style, outline: "none", cursor: "text" }}
      contentEditable
      suppressContentEditableWarning
      spellCheck={false}
      onFocus={(e) => { e.currentTarget.dataset.before = e.currentTarget.textContent; }}
      onKeyDown={(e) => { if (!multiline && e.key === "Enter") { e.preventDefault(); e.currentTarget.blur(); } }}
      onBlur={(e) => { const t = e.currentTarget.textContent; if (t !== e.currentTarget.dataset.before) onCommit(t); }}
      title="Click to edit"
    >{value}</Tag>
  );
}

function PreviewTable({ table, theme, narrow, onEdit, editPath }) {
  const cellEdit = (path) => (onEdit && editPath ? (v) => onEdit([...editPath, ...path], v) : undefined);
  return (
    <div className="overflow-x-auto max-w-4xl mx-auto mt-6">
      <table className="w-full border-collapse text-left" style={{ fontSize: narrow ? 13 : 16 }}>
        <thead>
          <tr>
            {table.headers.map((h, i) => (
              <th key={i} className="px-4 py-3 font-bold align-top" style={{ background: "rgba(0,0,0,0.45)", color: i === 0 ? "#fff" : theme.accent, borderBottom: "2px solid rgba(255,255,255,0.15)" }}>
                <Editable value={h} onCommit={cellEdit(["headers", i])} />
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {table.rows.map((r, ri) => (
            <tr key={ri} style={{ background: ri % 2 ? "rgba(255,255,255,0.03)" : "transparent" }}>
              {r.map((c, ci) => (
                <td key={ci} className="px-4 py-3 align-top" style={{ color: ci === 0 ? "#e2e8f0" : "#cbd5e1", fontWeight: ci === 0 ? 600 : 400, borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
                  <Editable value={c} onCommit={cellEdit(["rows", ri, ci])} />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function tableHTML(table, theme) {
  const e = (s = "") => String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  return `<table class="ptable"><thead><tr>${table.headers.map((h, i) => `<th${i === 0 ? "" : ` style="color:${theme.accent}"`}>${e(h)}</th>`).join("")}</tr></thead>
<tbody>${table.rows.map((r) => `<tr>${r.map((c, ci) => `<td${ci === 0 ? ' class="c0"' : ""}>${e(c)}</td>`).join("")}</tr>`).join("")}</tbody></table>`;
}




/* ---------- free-placed draggable / resizable photos ---------- */
const clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, n));

function FreeImageLayer({ items, onChange, rootRef }) {
  const drag = useRef(null);
  useEffect(() => {
    const onMove = (e) => {
      if (!drag.current || !rootRef.current) return;
      const rect = rootRef.current.getBoundingClientRect();
      const d = drag.current;
      const dxPct = ((e.clientX - d.startX) / rect.width) * 100;
      const dy = e.clientY - d.startY;
      onChange(items.map((it) => {
        if (it.id !== d.id) return it;
        if (d.mode === "move") return { ...it, xPct: clamp(d.ox + dxPct, -5, 98), yPx: Math.max(0, d.oy + dy) };
        const nw = clamp(d.ow + dxPct, 5, 120);
        const nh = it.stretch ? Math.max(20, d.oh + dy) : 0;
        return { ...it, wPct: nw, hPx: nh };
      }));
    };
    const onUp = () => { drag.current = null; };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => { window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); };
  }, [items, onChange, rootRef]);

  return (
    <>
      {items.map((it) => (
        <div key={it.id} style={{ position: "absolute", left: `${it.xPct}%`, top: it.yPx, width: `${it.wPct}%`, zIndex: 40 }}>
          <img src={it.src} alt="" draggable={false}
            onMouseDown={(e) => { e.preventDefault(); drag.current = { mode: "move", id: it.id, startX: e.clientX, startY: e.clientY, ox: it.xPct, oy: it.yPx }; }}
            style={{ width: "100%", height: it.stretch && it.hPx ? it.hPx : "auto", display: "block", borderRadius: 6, cursor: "move", boxShadow: "0 2px 14px rgba(0,0,0,.45)", outline: "2px solid rgba(14,165,233,.7)", outlineOffset: 1 }} />
          <button onClick={() => onChange(items.filter((x) => x.id !== it.id))}
            style={{ position: "absolute", top: -11, right: -11, width: 22, height: 22, borderRadius: 11, background: "#ef4444", color: "#fff", fontSize: 13, lineHeight: "22px", textAlign: "center", border: "2px solid #fff", cursor: "pointer", zIndex: 2 }}>×</button>
          <button onClick={() => onChange(items.map((x) => (x.id === it.id ? { ...x, stretch: !x.stretch, hPx: x.stretch ? 0 : Math.round((rootRef.current?.getBoundingClientRect().width || 600) * (it.wPct / 100) * 0.66) } : x)))}
            title="Toggle stretch (free height)"
            style={{ position: "absolute", top: -11, left: -11, width: 22, height: 22, borderRadius: 11, background: it.stretch ? "#0ea5e9" : "#334155", color: "#fff", fontSize: 11, lineHeight: "22px", textAlign: "center", border: "2px solid #fff", cursor: "pointer", zIndex: 2 }}>⤢</button>
          <div onMouseDown={(e) => { e.preventDefault(); e.stopPropagation(); drag.current = { mode: "resize", id: it.id, startX: e.clientX, startY: e.clientY, ow: it.wPct, oh: it.hPx || 0 }; }}
            style={{ position: "absolute", bottom: -8, right: -8, width: 18, height: 18, borderRadius: 4, background: "#0ea5e9", border: "2px solid #fff", cursor: "nwse-resize", zIndex: 2 }} />
        </div>
      ))}
    </>
  );
}

function overlaysHTML(items) {
  if (!items || !items.length) return "";
  return items.map((it) => `<img src="${it.src}" alt="" style="position:absolute;left:${it.xPct}%;top:${it.yPx}px;width:${it.wPct}%;${it.stretch && it.hPx ? `height:${it.hPx}px;` : ""}border-radius:6px;z-index:5">`).join("");
}


